INSERT INTO metric_target (
    plant_id,
    metric_id,
    period_id,
    yellow_limit,
    green_limit,
    updated_at
)
SELECT
    1,
    nt.metric_id,
    p.period_id,
    ROUND(nt.yellow_limit::numeric,4),
    ROUND(nt.green_limit::numeric,4),
    NOW()
FROM new_targets nt
CROSS JOIN period p
WHERE p.year = 2026
ON CONFLICT (plant_id, metric_id, period_id)
DO UPDATE SET
    yellow_limit = EXCLUDED.yellow_limit,
    green_limit = EXCLUDED.green_limit,
    updated_at = NOW();